"use strict";parserFactory.register("truyenfull.vn",()=>new TruyenfullParser);class TruyenfullParser extends Parser{constructor(){super()}getChapterUrls(e,t){return this.getChapterUrlsFromMultipleTocPages(e,TruyenfullParser.extractPartialChapterList,TruyenfullParser.getUrlsOfTocPages,t)}static getUrlsOfTocPages(e){let t=[],r=e.querySelector("input#total-page");if(null!=r){let l=parseInt(r.getAttribute("value"));for(let r=2;r<=l;++r)t.push(`${e.baseURI}trang-${r}/`)}return t}static extractPartialChapterList(e){return[...e.querySelectorAll("ul.list-chapter a")].map(e=>util.hyperLinkToChapter(e))}findContent(e){return e.querySelector("div.chapter-c")}extractTitleImpl(e){return e.querySelector("h3.title")}extractAuthor(e){let t=e.querySelector("a[itemprop='author']");return null===t?super.extractAuthor(e):t.textContent}findChapterTitle(e){let t=e.querySelector("a.chapter-title");return null===t?super.findChapterTitle(e):t.textContent}findCoverImageUrl(e){return util.getFirstImgSrc(e,"div.book")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div.desc-text")]}}